package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.AFWIJKEND_REGIME_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class ZetAfwijkendRegimeVoorMonitoren extends AbstractRekenCommand {
    private static final LocalDate START_AFWIJKEND_REGIME_MONITOREN = new LocalDate(2021, 12, 31);

    public static final ImmutableSet<LnedefRegBv> UITSLUITEN_REGIME_VOOR_MONITOREN =
            ImmutableSet.of(LnedefRegBv.VD_BV_10_UKAG_NBV, LnedefRegBv.VD_BV_10_ABO__NBV, LnedefRegBv.VD_BV_10_AWWV_NBV, LnedefRegBv.VD_BV_10_KWG__NBB,
                    LnedefRegBv.VD_BV_12_VVI__NBV, LnedefRegBv.NBB_NFF, LnedefRegBv.VD_BV_10_FTSW_NBB, LnedefRegBv.VD_BV_50_VAC_TOE_NBB, LnedefRegBv.VD_BV_50_KOSTEN_NBB,
                    LnedefRegBv.VD_BV_30_KOSTEN_NBV, LnedefRegBv.VD_BV_10_MOB_VERG_NBB);

    @Override
    protected boolean execute(RekenContext rekenContext) {
        Persoon persoon = rekenContext.getUnchecked(PERSOON_KEY);
        RekenTijd rekenTijd = rekenContext.getUnchecked(REKENTIJD_KEY);
        LoonElementManager manager = rekenContext.getUnchecked(LOONELEMENT_MANAGER_KEY);

        if (rekenTijd.beginDatum.isAfter((START_AFWIJKEND_REGIME_MONITOREN))) {
            persoon.getOpdrachten().stream()
                    .filter(this::bevatHoedanigheidMonitor)
                    .forEach(opdracht -> zetAfwijkendRegimePerOpdracht(opdracht, manager));
        }
        return CONTINUE_PROCESSING;
    }

    private void zetAfwijkendRegimePerOpdracht(Opdracht opdracht, LoonElementManager manager) {
        for (LoonElement loonElement : manager.getOpdrachtsElementen(opdracht)) {
            if (!UITSLUITEN_REGIME_VOOR_MONITOREN.contains(loonElement.getRegimeBv())) {
                loonElement.putProperty(AFWIJKEND_REGIME_KEY, LnedefRegBv.VD_BV_10_BZ___TV);
            }
        }
    }

    private boolean bevatHoedanigheidMonitor(Opdracht opdracht) {
        return opdracht.getHoedanigheid() == Hoedanigheid.MONITOREN;
    }
}
